# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, List, Set
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    name: str
    inventory: Dict[str, int]  # item_id -> quantity
    websocket: websockets.WebSocketServerProtocol

class MMOGameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.trade_requests: Dict[str, Dict] = {}
        self.trade_sessions: Dict[str, Dict] = {}
        self.connection_lock = asyncio.Lock()
        self.item_lock = asyncio.Lock()
        self.next_item_id = 1

    async def handle_client(self, websocket, path):
        player_id = None
        try:
            async for message in websocket:
                data = json.loads(message)
                command = data.get('command')
                
                if command == 'login':
                    player_id = await self.handle_login(websocket, data)
                elif command == 'get_inventory':
                    await self.handle_get_inventory(player_id, websocket)
                elif command == 'trade_request':
                    await self.handle_trade_request(player_id, data, websocket)
                elif command == 'trade_response':
                    await self.handle_trade_response(player_id, data, websocket)
                elif command == 'transfer_item':
                    await self.handle_transfer_item(player_id, data, websocket)
                elif command == 'create_item':
                    await self.handle_create_item(player_id, data, websocket)
                    
        except websockets.exceptions.ConnectionClosed:
            if player_id:
                await self.handle_disconnect(player_id)
        except Exception as e:
            print(f"Error handling client: {e}")

    async def handle_login(self, websocket, data):
        player_name = data.get('name')
        player_id = str(uuid.uuid4())
        
        player = Player(id=player_id, name=player_name, inventory={}, websocket=websocket)
        self.players[player_id] = player
        
        # Send player info back
        await websocket.send(json.dumps({
            'command': 'login_success',
            'player_id': player_id,
            'player_name': player_name
        }))
        
        return player_id

    async def handle_disconnect(self, player_id):
        if player_id in self.players:
            del self.players[player_id]
            print(f"Player {player_id} disconnected")

    async def handle_get_inventory(self, player_id, websocket):
        player = self.players.get(player_id)
        if not player:
            return
            
        inventory_data = []
        for item_id, quantity in player.inventory.items():
            if item_id in self.items:
                item = self.items[item_id]
                inventory_data.append({
                    'item_id': item.id,
                    'name': item.name,
                    'type': item.type,
                    'value': item.value,
                    'quantity': quantity
                })
        
        await websocket.send(json.dumps({
            'command': 'inventory_data',
            'inventory': inventory_data
        }))

    async def handle_create_item(self, player_id, data, websocket):
        player = self.players.get(player_id)
        if not player:
            return
            
        item_type = data.get('type')
        item_name = data.get('name')
        item_value = data.get('value', 0)
        
        async with self.item_lock:
            item_id = f"item_{self.next_item_id}"
            self.next_item_id += 1
            
            item = Item(
                id=item_id,
                name=item_name,
                type=item_type,
                value=item_value,
                owner_id=player_id
            )
            
            self.items[item_id] = item
            
            # Add to player inventory
            if item_id not in player.inventory:
                player.inventory[item_id] = 0
            player.inventory[item_id] += 1
            
            # Notify player
            await websocket.send(json.dumps({
                'command': 'item_created',
                'item': {
                    'id': item.id,
                    'name': item.name,
                    'type': item.type,
                    'value': item.value
                }
            }))

    async def handle_transfer_item(self, player_id, data, websocket):
        from_player = self.players.get(player_id)
        to_player_id = data.get('to_player_id')
        item_id = data.get('item_id')
        quantity = data.get('quantity', 1)
        
        if not from_player or to_player_id not in self.players:
            await websocket.send(json.dumps({
                'command': 'error',
                'message': 'Invalid player'
            }))
            return
            
        to_player = self.players[to_player_id]
        
        # Check if player has the item
        if item_id not in from_player.inventory or from_player.inventory[item_id] < quantity:
            await websocket.send(json.dumps({
                'command': 'error',
                'message': 'Not enough items'
            }))
            return
            
        # Concurrent transfer using lock
        async with self.item_lock:
            # Remove from sender
            from_player.inventory[item_id] -= quantity
            if from_player.inventory[item_id] <= 0:
                del from_player.inventory[item_id]
            
            # Add to receiver
            if item_id not in to_player.inventory:
                to_player.inventory[item_id] = 0
            to_player.inventory[item_id] += quantity
            
            # Update item owner if needed
            if item_id in self.items:
                self.items[item_id].owner_id = to_player_id
            
            # Notify both players
            await websocket.send(json.dumps({
                'command': 'transfer_success',
                'item_id': item_id,
                'quantity': quantity,
                'to_player': to_player_id
            }))
            
            # Notify receiver if online
            if to_player.websocket.open:
                await to_player.websocket.send(json.dumps({
                    'command': 'received_item',
                    'item_id': item_id,
                    'quantity': quantity,
                    'from_player': player_id
                }))

    async def handle_trade_request(self, player_id, data, websocket):
        requester = self.players.get(player_id)
        target_player_id = data.get('target_player_id')
        
        if not requester or target_player_id not in self.players:
            await websocket.send(json.dumps({
                'command': 'error',
                'message': 'Invalid player'
            }))
            return
            
        target_player = self.players[target_player_id]
        
        trade_id = str(uuid.uuid4())
        self.trade_requests[trade_id] = {
            'requester': player_id,
            'target': target_player_id,
            'status': 'pending',
            'items_offered': [],
            'items_requested': []
        }
        
        # Notify target player
        if target_player.websocket.open:
            await target_player.websocket.send(json.dumps({
                'command': 'trade_request',
                'trade_id': trade_id,
                'requester': player_id,
                'requester_name': requester.name
            }))

    async def handle_trade_response(self, player_id, data, websocket):
        trade_id = data.get('trade_id')
        accept = data.get('accept', False)
        
        if trade_id not in self.trade_requests:
            await websocket.send(json.dumps({
                'command': 'error',
                'message': 'Trade not found'
            }))
            return
            
        request = self.trade_requests[trade_id]
        
        if request['target'] != player_id:
            await websocket.send(json.dumps({
                'command': 'error',
                'message': 'Not authorized to respond to this trade'
            }))
            return
            
        if not accept:
            del self.trade_requests[trade_id]
            await websocket.send(json.dumps({
                'command': 'trade_declined'
            }))
            return
            
        # Accept trade
        request['status'] = 'accepted'
        self.trade_sessions[trade_id] = {
            'requester': request['requester'],
            'target': request['target'],
            'items_offered': request['items_offered'],
            'items_requested': request['items_requested']
        }
        
        # Notify both players
        requester = self.players[request['requester']]
        target = self.players[request['target']]
        
        if requester.websocket.open:
            await requester.websocket.send(json.dumps({
                'command': 'trade_accepted',
                'trade_id': trade_id
            }))
        
        if target.websocket.open:
            await target.websocket.send(json.dumps({
                'command': 'trade_accepted',
                'trade_id': trade_id
            }))

    async def run_trade(self, trade_id):
        if trade_id not in self.trade_sessions:
            return
            
        session = self.trade_sessions[trade_id]
        requester = self.players[session['requester']]
        target = self.players[session['target']]
        
        # Execute trade
        try:
            async with self.item_lock:
                # Process item transfers
                for item_id, quantity in session['items_offered']:
                    if item_id in requester.inventory and requester.inventory[item_id] >= quantity:
                        requester.inventory[item_id] -= quantity
                        if requester.inventory[item_id] <= 0:
                            del requester.inventory[item_id]
                        
                        if item_id not in target.inventory:
                            target.inventory[item_id] = 0
                        target.inventory[item_id] += quantity
                        
                        if item_id in self.items:
                            self.items[item_id].owner_id = target.id
                
                for item_id, quantity in session['items_requested']:
                    if item_id in target.inventory and target.inventory[item_id] >= quantity:
                        target.inventory[item_id] -= quantity
                        if target.inventory[item_id] <= 0:
                            del target.inventory[item_id]
                        
                        if item_id not in requester.inventory:
                            requester.inventory[item_id] = 0
                        requester.inventory[item_id] += quantity
                        
                        if item_id in self.items:
                            self.items[item_id].owner_id = requester.id
                
                # Clean up
                del self.trade_sessions[trade_id]
                
                # Notify completion
                if requester.websocket.open:
                    await requester.websocket.send(json.dumps({
                        'command': 'trade_complete'
                    }))
                
                if target.websocket.open:
                    await target.websocket.send(json.dumps({
                        'command': 'trade_complete'
                    }))
                    
        except Exception as e:
            print(f"Trade error: {e}")
            # Clean up on error
            if trade_id in self.trade_sessions:
                del self.trade_sessions[trade_id]

# Start the server
async def main():
    server = MMOGameServer()
    start_server = websockets.serve(server.handle_client, "localhost", 8765)
    await start_server
    print("MMO Server started on ws://localhost:8765")
    await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())